{"code":"// Fetch unresolved Sentry issues for the billing project
const unresolvedIssues = sentry__list_issues({
  project: "billing",
  status: "unresolved"
});

// Get the count of unresolved issues
const count = unresolvedIssues.length;

// Extract just the IDs
const issueIds = unresolvedIssues.map(issue => issue.id);

// Return the count and IDs
{
  count,
  issueIds
}"}
